const DEFAULT_CATALOG_PRODUCTS_CACHE_TTL_SEC = 60
const DEFAULT_CATALOG_CURRENT_CACHE_TTL_SEC = 60
const DEFAULT_CATEGORY_LIST_CACHE_TTL_SEC = 60
const DEFAULT_CATEGORY_PRODUCTS_FIRST_PAGE_CACHE_TTL_SEC = 60
const DEFAULT_CATEGORY_PRODUCTS_NEXT_PAGE_CACHE_TTL_SEC = 30

export const CATALOG_PRODUCTS_CACHE_TTL_SEC =
	Number(
		process.env.CATALOG_PRODUCTS_CACHE_TTL_SEC ??
			DEFAULT_CATALOG_PRODUCTS_CACHE_TTL_SEC
	) || DEFAULT_CATALOG_PRODUCTS_CACHE_TTL_SEC

export const CATALOG_CURRENT_CACHE_TTL_SEC =
	Number(
		process.env.CATALOG_CURRENT_CACHE_TTL_SEC ?? CATALOG_PRODUCTS_CACHE_TTL_SEC
	) || DEFAULT_CATALOG_CURRENT_CACHE_TTL_SEC

export const CATALOG_CACHE_VERSION = 'catalog'
export const CATALOG_TYPE_CACHE_VERSION = 'catalog-type'
export const CATEGORY_LIST_CACHE_VERSION = 'categories-v1'
export const PRODUCTS_CACHE_VERSION = 'products-v2'
export const CATEGORY_PRODUCTS_CACHE_VERSION = 'category-products-v2'

export const CATEGORY_LIST_CACHE_TTL_SEC =
	Number(
		process.env.CATEGORY_LIST_CACHE_TTL_SEC ??
			process.env.CATALOG_CURRENT_CACHE_TTL_SEC ??
			CATALOG_PRODUCTS_CACHE_TTL_SEC
	) || DEFAULT_CATEGORY_LIST_CACHE_TTL_SEC

export const CATEGORY_PRODUCTS_FIRST_PAGE_CACHE_TTL_SEC =
	Number(
		process.env.CATEGORY_PRODUCTS_FIRST_PAGE_CACHE_TTL_SEC ??
			CATALOG_PRODUCTS_CACHE_TTL_SEC
	) || DEFAULT_CATEGORY_PRODUCTS_FIRST_PAGE_CACHE_TTL_SEC

export const CATEGORY_PRODUCTS_NEXT_PAGE_CACHE_TTL_SEC =
	Number(
		process.env.CATEGORY_PRODUCTS_NEXT_PAGE_CACHE_TTL_SEC ??
			DEFAULT_CATEGORY_PRODUCTS_NEXT_PAGE_CACHE_TTL_SEC
	) || DEFAULT_CATEGORY_PRODUCTS_NEXT_PAGE_CACHE_TTL_SEC
